            // @ts-expect-error TS2339
            max_length: this.model.config.decoder.max_position_embeddings,
            decoder_input_ids,
            ...generate_kwargs,
        });

        // Decode output
        const decoded = this.tokenizer.batch_decode(/** @type {Tensor} */(output))[0];

        // Parse answer
        const match = decoded.match(/<s_answer>(.*?)<\/s_answer>/);
        let answer = null;
        if (match && match.length >= 2) {
            answer = match[1].trim();
        }
        return [{ answer }];
    }
}
```

---

### 4. **Task Registration Pattern**

Tasks are registered in the `SUPPORTED_TASKS` object (lines 3100-3390). Here's the pattern for both examples:

```javascript
"image-to-text": {
    "tokenizer": AutoTokenizer,
    "pipeline": ImageToTextPipeline,
    "model": AutoModelForVision2Seq,
    "processor": AutoProcessor,
    "default": {
        "model": "Xenova/vit-gpt2-image-captioning",
    },
    "type": "multimodal",
},

"document-question-answering": {
    "tokenizer": AutoTokenizer,
    "pipeline": DocumentQuestionAnsweringPipeline,
    "model": AutoModelForDocumentQuestionAnswering,
    "processor": AutoProcessor,
    "default": {
        "model": "Xenova/donut-base-finetuned-docvqa",
    },
    "type": "multimodal",
},
```

**For your `image-text-to-text` pipeline, follow this pattern:**

```javascript
"image-text-to-text": {
    "tokenizer": AutoTokenizer,
    "pipeline": ImageTextToTextPipeline,
    "model": AutoModelForImageTextToText,
    "processor": AutoProcessor,
    "default": {
        "model": "<MODEL_NAME>",  // Specify appropriate default model
    },
    "type": "multimodal",
},
```

---

### 5. **Processor/Tokenizer Pattern for Image+Text Inputs**

Key pattern from DocumentQuestionAnsweringPipeline (handles both image and text):

```javascript
// 1. Prepare image(s)
const preparedImages = await prepareImages(images);

// 2. Process image(s) to get pixel_values
const { pixel_values } = await this.processor(preparedImages);

// 3. Tokenize text (e.g., question/prompt)
const text_inputs = this.tokenizer(text, {
    padding: true,
    truncation: true,
});

// 4. Pass both to model
const output = await this.model.generate({
    inputs: pixel_values,
    decoder_input_ids: text_inputs.input_ids,
    ...generate_kwargs,
});

// 5. Decode output with tokenizer
const decoded = this.tokenizer.batch_decode(output);
```

Alternative pattern from ZeroShotImageClassificationPipeline:
```javascript
// For models expecting both text and pixel inputs simultaneously:
const output = await this.model({ ...text_inputs, pixel_values });
```

