/**
 * @typedef {Object} ImageTextToTextSingle
 * @property {string} generated_text The generated text.
 * @typedef {ImageTextToTextSingle[]} ImageTextToTextOutput
 *
 * @callback ImageTextToTextPipelineCallback Process an image and a text prompt, returning model-generated text.
 * @param {ImagePipelineInputs} images The image(s) to process.
 * @param {string|string[]} texts The text prompt(s) to condition the generation on.
 * @param {Partial<import('./generation/configuration_utils.js').GenerationConfig>} [options] Additional keyword arguments to pass along to the generate method of the model.
 * @returns {Promise<ImageTextToTextOutput|ImageTextToTextOutput[]>} An object (or array of objects) containing the generated text(s).
 *
 * @typedef {TextImagePipelineConstructorArgs & ImageTextToTextPipelineCallback & Disposable} ImageTextToTextPipelineType
 */

/**
 * Image-text-to-text pipeline using any `AutoModelForImageTextToText`. This pipeline accepts
 * an image and a text prompt, processes both through a multimodal language model, and returns
 * the generated text. Suitable for visual question answering, image captioning with prompts,
 * and other vision-language tasks.
 *
 * **Example:** Describe an image with `onnx-community/SmolVLM-256M-Instruct`.
 * ```javascript
 * const pipe = await pipeline('image-text-to-text', 'onnx-community/SmolVLM-256M-Instruct');
 * const image = 'https://huggingface.co/datasets/Xenova/transformers.js-docs/resolve/main/cats.jpg';
 * const text = '<image>Describe this image in one sentence.';
 * const output = await pipe(image, text);
 * // [{ generated_text: 'Two cats are resting together on a couch.' }]
 * ```
 */
export class ImageTextToTextPipeline extends (/** @type {new (options: TextImagePipelineConstructorArgs) => ImageTextToTextPipelineType} */ (Pipeline)) {

    /**
     * Create a new ImageTextToTextPipeline.
     * @param {TextImagePipelineConstructorArgs} options An object used to instantiate the pipeline.
     */
    constructor(options) {
        super(options);
    }

    /** @type {ImageTextToTextPipelineCallback} */
    async _call(images, texts, generate_kwargs = {}) {
        const isBatched = Array.isArray(images);
        const preparedImages = await prepareImages(images);
        const preparedTexts = Array.isArray(texts) ? texts : [texts];

        const toReturn = [];
        for (let i = 0; i < preparedImages.length; ++i) {
            const image = preparedImages[i];
            const text = preparedTexts[Math.min(i, preparedTexts.length - 1)];

            // Process image and text together through the multimodal processor
            const inputs = await this.processor(image, text);

            // Generate output token ids
            const outputIds = await this.model.generate({ ...inputs, ...generate_kwargs });

            // Slice off input tokens to obtain only the newly generated tokens
            const newTokens = /** @type {Tensor} */(outputIds).slice(null, [inputs.input_ids.dims[1], null]);

            // Decode generated tokens into text
            const decoded = this.tokenizer.batch_decode(newTokens, {
                skip_special_tokens: true,
            }).map(x => ({ generated_text: x.trim() }));

            toReturn.push(decoded);
        }

        return isBatched ? toReturn : toReturn[0];
    }
}


